1	/**
2	 * The Oculus — web dashboard apparatus.
3	 *
4	 * Serves a web dashboard via Hono. Plugins contribute pages as static asset
5	 * directories and custom API routes through kit contributions. Guild tools are
6	 * automatically exposed as REST endpoints.
7	 */
8	
9	import fs from 'node:fs';
10	import path from 'node:path';
11	import { Hono } from 'hono';
12	import { serve } from '@hono/node-server';
13	import type { Server } from 'node:http';
14	import { z } from 'zod';
15	
16	import type { Plugin, StartupContext, LoadedKit, LoadedApparatus } from '@shardworks/nexus-core';
17	import { guild, VERSION } from '@shardworks/nexus-core';
18	import type { InstrumentariumApi } from '@shardworks/tools-apparatus';
19	import { tool } from '@shardworks/tools-apparatus';
20	
21	import type { OculusApi, OculusConfig, OculusKit, PageContribution, RouteContribution } from './types.ts';
22	
23	// ── MIME types ────────────────────────────────────────────────────────
24	
25	const MIME_TYPES: Record<string, string> = {
26	  '.html': 'text/html; charset=utf-8',
27	  '.css': 'text/css; charset=utf-8',
28	  '.js': 'application/javascript; charset=utf-8',
29	  '.mjs': 'application/javascript; charset=utf-8',
30	  '.json': 'application/json; charset=utf-8',
31	  '.png': 'image/png',
32	  '.jpg': 'image/jpeg',
33	  '.jpeg': 'image/jpeg',
34	  '.gif': 'image/gif',
35	  '.svg': 'image/svg+xml',
36	  '.ico': 'image/x-icon',
37	  '.woff': 'font/woff',
38	  '.woff2': 'font/woff2',
39	  '.ttf': 'font/ttf',
40	  '.map': 'application/json',
41	};
42	
43	function getMimeType(filePath: string): string {
44	  const ext = path.extname(filePath).toLowerCase();
45	  return MIME_TYPES[ext] ?? 'application/octet-stream';
46	}
47	
48	// ── Tool→REST mapping helpers ─────────────────────────────────────────
49	
50	export function toolNameToRoute(name: string): string {
51	  const idx = name.indexOf('-');
52	  if (idx === -1) return `/api/${name}`;
53	  return `/api/${name.slice(0, idx)}/${name.slice(idx + 1)}`;
54	}
55	
56	export function permissionToMethod(permission: string | undefined): 'GET' | 'POST' | 'DELETE' {
57	  if (permission === undefined) return 'GET';
58	  const level = permission.includes(':')
59	    ? permission.slice(permission.lastIndexOf(':') + 1)
60	    : permission;
61	  if (level === 'read') return 'GET';
62	  if (level === 'write' || level === 'admin') return 'POST';
63	  if (level === 'delete') return 'DELETE';
64	  return 'POST';
65	}
66	
67	// ── Query param coercion ──────────────────────────────────────────────
68	
69	function isNumberSchema(schema: z.ZodTypeAny): boolean {
70	  let inner: z.ZodTypeAny = schema;
71	  if (inner instanceof z.ZodOptional) inner = inner.unwrap() as z.ZodTypeAny;
72	  if (inner instanceof z.ZodDefault) inner = inner.unwrap() as z.ZodTypeAny;
73	  if (inner instanceof z.ZodOptional) inner = inner.unwrap() as z.ZodTypeAny;
74	  return inner instanceof z.ZodNumber;
75	}
76	
77	function isBooleanSchema(schema: z.ZodTypeAny): boolean {
78	  let inner: z.ZodTypeAny = schema;
79	  if (inner instanceof z.ZodOptional) inner = inner.unwrap() as z.ZodTypeAny;
80	  if (inner instanceof z.ZodDefault) inner = inner.unwrap() as z.ZodTypeAny;
81	  if (inner instanceof z.ZodOptional) inner = inner.unwrap() as z.ZodTypeAny;
82	  return inner instanceof z.ZodBoolean;
83	}
84	
85	export function coerceParams(
86	  shape: Record<string, z.ZodTypeAny>,
87	  params: Record<string, string>,
88	): Record<string, unknown> {
89	  const result: Record<string, unknown> = { ...params };
90	  for (const [key, schema] of Object.entries(shape)) {
91	    const value = result[key];
92	    if (typeof value !== 'string') continue;
93	    if (isNumberSchema(schema)) {
94	      result[key] = Number(value);
95	    } else if (isBooleanSchema(schema)) {
96	      result[key] = value === 'true';
97	    }
98	  }
99	  return result;
100	}
101	
102	// ── Chrome injection ─────────────────────────────────────────────────
103	
104	export function injectChrome(html: string, stylesheetPath: string, navHtml: string): string {
105	  // Check for </head> case-insensitively
106	  const headCloseMatch = html.match(/<\/head>/i);
107	  const bodyOpenMatch = html.match(/<body[^>]*>/i);
108	
109	  // If neither tag present, return unmodified
110	  if (!headCloseMatch && !bodyOpenMatch) return html;
111	
112	  let result = html;
113	
114	  // Insert stylesheet link before </head>
115	  if (headCloseMatch && headCloseMatch.index !== undefined) {
116	    const idx = headCloseMatch.index;
117	    result =
118	      result.slice(0, idx) +
119	      `<link rel="stylesheet" href="${stylesheetPath}">` +
120	      result.slice(idx);
121	  }
122	
123	  // Insert nav after <body...>
124	  // Need to recalculate position after potential head insertion
125	  const bodyMatch = result.match(/<body[^>]*>/i);
126	  if (bodyMatch && bodyMatch.index !== undefined) {
127	    const idx = bodyMatch.index + bodyMatch[0].length;
128	    result = result.slice(0, idx) + navHtml + result.slice(idx);
129	  }
130	
131	  return result;
132	}
133	
134	function buildNavHtml(pages: PageContribution[]): string {
135	  const pageLinks = pages
136	    .map((p) => `<a href="/pages/${p.id}/">${p.title}</a>`)
137	    .join('\n  ');
138	  return `<nav id="oculus-nav">
139	  <a href="/">Guild</a>
140	  ${pageLinks}
141	</nav>`;
142	}
143	
144	// ── HTML escaping ─────────────────────────────────────────────────────
145	
146	function escapeHtml(text: string): string {
147	  return text
148	    .replace(/&/g, '&amp;')
149	    .replace(/</g, '&lt;')
150	    .replace(/>/g, '&gt;');
151	}
152	
153	// ── Tool param extraction (reimplemented from tools-show) ────────────
154	
155	interface ParamInfo {
156	  type: string;
157	  description: string | null;
158	  optional: boolean;
159	}
160	
161	function zodTypeToJsonType(zodType: z.ZodType): string {
162	  if (zodType instanceof z.ZodString) return 'string';
163	  if (zodType instanceof z.ZodNumber) return 'number';
164	  if (zodType instanceof z.ZodBoolean) return 'boolean';
165	  if (zodType instanceof z.ZodArray) return 'array';
166	  if (zodType instanceof z.ZodObject) return 'object';
167	  if (zodType instanceof z.ZodEnum) return 'string';
168	  if (zodType instanceof z.ZodLiteral) return typeof zodType._def.values[0];
169	  if (zodType instanceof z.ZodUnion) return 'union';
170	  if (zodType instanceof z.ZodNullable) return zodTypeToJsonType(zodType.unwrap() as z.ZodType);
171	  return 'unknown';
172	}
173	
174	function extractSingleParam(zodType: z.ZodType): ParamInfo {
175	  let isOptional = false;
176	  let inner: z.ZodType = zodType;
177	
178	  if (inner instanceof z.ZodOptional) {
179	    isOptional = true;
180	    inner = inner.unwrap() as z.ZodType;
181	  }
182	  if (inner instanceof z.ZodDefault) {
183	    isOptional = true;
184	    inner = inner.unwrap() as z.ZodType;
185	  }
186	
187	  return {
188	    type: zodTypeToJsonType(inner),
189	    description: inner.description ?? null,
190	    optional: isOptional,
191	  };
192	}
193	
194	function extractParams(schema: z.ZodObject<z.ZodRawShape>): Record<string, ParamInfo> {
195	  const shape = schema.shape;
196	  const result: Record<string, ParamInfo> = {};
197	  for (const [key, zodType] of Object.entries(shape)) {
198	    result[key] = extractSingleParam(zodType as z.ZodType);
199	  }
200	  return result;
201	}
202	
203	// ── Apparatus factory ─────────────────────────────────────────────────
204	
205	export function createOculus(): Plugin {
206	  let serverPort = 7470;
207	  let server: Server | null = null;
208	
209	  const api: OculusApi = {
210	    port(): number {
211	      return serverPort;
212	    },
213	  };
214	
215	  return {
216	    apparatus: {
217	      requires: ['tools'],
218	      consumes: ['pages', 'routes'],
219	      provides: api,
220	
221	      async start(ctx: StartupContext): Promise<void> {
222	        const g = guild();
223	        const oculusConfig: OculusConfig = g.guildConfig().oculus ?? {};
224	        const port = oculusConfig.port ?? 7470;
225	
226	        const app = new Hono();
227	
228	        // Track registered pages and custom route paths
229	        const pages: PageContribution[] = [];
230	        const customRoutePaths = new Set<string>();
231	        const mappedToolRoutes = new Set<string>();
232	
233	        // ── Custom route registration helper ─────────────────────────
234	        function registerCustomRoute(route: RouteContribution, pluginId: string): void {
235	          if (!route.path.startsWith('/api/')) {
236	            console.warn(`[oculus] Custom route "${route.path}" from "${pluginId}" must start with /api/ — skipped`);
237	            return;
238	          }
239	          const method = route.method.toLowerCase() as keyof typeof app;
240	          (app[method] as (path: string, handler: (c: unknown) => unknown) => void)(
241	            route.path,
242	            route.handler as (c: unknown) => unknown,
243	          );
244	          customRoutePaths.add(route.path);
245	        }
246	
247	        // ── Page serving helper ───────────────────────────────────────
248	        function resolveDirForPackage(packageName: string, dir: string): string {
249	          return path.join(g.home, 'node_modules', packageName, dir);
250	        }
251	
252	        function registerPage(page: PageContribution, resolvedDir: string): void {
253	          pages.push({ ...page });
254	
255	          app.get(`/pages/${page.id}/*`, async (c) => {
256	            const requestPath = c.req.path;
257	            const prefix = `/pages/${page.id}/`;
258	            const filePath = requestPath.slice(prefix.length) || 'index.html';
259	
260	            // Prevent directory traversal
261	            if (filePath.includes('..')) {
262	              return c.text('Not found', 404);
263	            }
264	
265	            const absolutePath = path.join(resolvedDir, filePath);
266	
267	            // Ensure file is within resolved dir
268	            if (!absolutePath.startsWith(resolvedDir)) {
269	              return c.text('Not found', 404);
270	            }
271	
272	            try {
273	              const content = fs.readFileSync(absolutePath);
274	              const mimeType = getMimeType(absolutePath);
275	
276	              // Only inject chrome for the root index.html
277	              const isIndexHtml = filePath === 'index.html' || filePath === '';
278	              if (isIndexHtml && mimeType.startsWith('text/html')) {
279	                const html = content.toString('utf-8');
280	                const navHtml = buildNavHtml(pages);
281	                const injected = injectChrome(html, '/static/style.css', navHtml);
282	                return new Response(injected, {
283	                  headers: { 'Content-Type': 'text/html; charset=utf-8' },
284	                });
285	              }
286	
287	              return new Response(content, {
288	                headers: { 'Content-Type': mimeType },
289	              });
290	            } catch {
291	              return c.text('Not found', 404);
292	            }
293	          });
294	        }
295	
296	        // ── Tool route registration helper ───────────────────────────
297	        function registerToolRoute(
298	          toolDef: import('@shardworks/tools-apparatus').ToolDefinition,
299	          instrumentarium: InstrumentariumApi,
300	        ): void {
301	          const routePath = toolNameToRoute(toolDef.name);
302	          const method = permissionToMethod(toolDef.permission);
303	
304	          if (mappedToolRoutes.has(routePath)) return;
305	
306	          if (customRoutePaths.has(routePath)) {
307	            console.warn(
308	              `[oculus] Tool route ${method} ${routePath} conflicts with custom route from plugin — skipped`,
309	            );
310	            return;
311	          }
312	
313	          void instrumentarium; // suppress unused warning
314	
315	          const shape = toolDef.params.shape as Record<string, z.ZodTypeAny>;
316	
317	          if (method === 'GET') {
318	            app.get(routePath, async (c) => {
319	              try {
320	                const rawQuery = c.req.query();
321	                const coerced = coerceParams(shape, rawQuery);
322	                const validated = toolDef.params.parse(coerced);
323	                const result = await toolDef.handler(validated);
324	                return c.json(result);
325	              } catch (err) {
326	                if (err instanceof z.ZodError) {
327	                  return c.json({ error: err.message, details: err.issues }, 400);
328	                }
329	                const message = err instanceof Error ? err.message : String(err);
330	                return c.json({ error: message }, 500);
331	              }
332	            });
333	          } else if (method === 'DELETE') {
334	            app.delete(routePath, async (c) => {
335	              try {
336	                const body = await c.req.json();
337	                const validated = toolDef.params.parse(body);
338	                const result = await toolDef.handler(validated);
339	                return c.json(result);
340	              } catch (err) {
341	                if (err instanceof z.ZodError) {
342	                  return c.json({ error: err.message, details: err.issues }, 400);
343	                }
344	                const message = err instanceof Error ? err.message : String(err);
345	                return c.json({ error: message }, 500);
346	              }
347	            });
348	          } else {
349	            app.post(routePath, async (c) => {
350	              try {
351	                const body = await c.req.json();
352	                const validated = toolDef.params.parse(body);
353	                const result = await toolDef.handler(validated);
354	                return c.json(result);
355	              } catch (err) {
356	                if (err instanceof z.ZodError) {
357	                  return c.json({ error: err.message, details: err.issues }, 400);
358	                }
359	                const message = err instanceof Error ? err.message : String(err);
360	                return c.json({ error: message }, 500);
361	              }
362	            });
363	          }
364	
365	          mappedToolRoutes.add(routePath);
366	        }
367	
368	        // ── Scan contributions from a kit ────────────────────────────
369	        function scanKit(kit: LoadedKit): void {
370	          const oculusKit = kit.kit as OculusKit;
371	
372	          if (oculusKit.routes) {
373	            for (const route of oculusKit.routes) {
374	              registerCustomRoute(route, kit.id);
375	            }
376	          }
377	
378	          if (oculusKit.pages) {
379	            for (const page of oculusKit.pages) {
380	              const resolvedDir = resolveDirForPackage(kit.packageName, page.dir);
381	              registerPage(page, resolvedDir);
382	            }
383	          }
384	        }
385	
386	        function scanApparatus(apparatus: LoadedApparatus): void {
387	          if (!apparatus.apparatus.supportKit) return;
388	          const oculusKit = apparatus.apparatus.supportKit as OculusKit;
389	
390	          if (oculusKit.routes) {
391	            for (const route of oculusKit.routes) {
392	              registerCustomRoute(route, apparatus.id);
393	            }
394	          }
395	
396	          if (oculusKit.pages) {
397	            for (const page of oculusKit.pages) {
398	              const resolvedDir = resolveDirForPackage(apparatus.packageName, page.dir);
399	              registerPage(page, resolvedDir);
400	            }
401	          }
402	        }
403	
404	        // ── Scan existing kits and apparatuses ───────────────────────
405	        for (const kit of g.kits()) {
406	          scanKit(kit);
407	        }
408	        for (const apparatus of g.apparatuses()) {
409	          scanApparatus(apparatus);
410	        }
411	
412	        // ── Register custom routes first ─────────────────────────────
413	        // (already done in scanKit/scanApparatus above)
414	
415	        // ── Register tool routes ─────────────────────────────────────
416	        const instrumentarium = g.apparatus<InstrumentariumApi>('tools');
417	        const allTools = instrumentarium.list();
418	        const patronTools = allTools.filter(
419	          (r) => !r.definition.callableBy || r.definition.callableBy.includes('patron'),
420	        );
421	
422	        for (const resolved of patronTools) {
423	          registerToolRoute(resolved.definition, instrumentarium);
424	        }
425	
426	        // ── GET /api/_status ─────────────────────────────────────────
427	        app.get('/api/_status', (c) => {
428	          const config = g.guildConfig();
429	          return c.json({
430	            guild: config.name,
431	            nexus: VERSION,
432	            home: g.home,
433	            model: config.settings?.model ?? '(not set)',
434	            port: port,
435	            apparatuses: g.apparatuses().map((a) => ({ id: a.id, version: a.version })),
436	            kits: g.kits().map((k) => ({ id: k.id, version: k.version })),
437	            failedPlugins: g.failedPlugins().map((f) => ({ id: f.id, reason: f.reason })),
438	            warnings: g.startupWarnings(),
439	            config: config,
440	          });
441	        });
442	
443	        // ── GET /api/_tools ──────────────────────────────────────────
444	        app.get('/api/_tools', (c) => {
445	          const tools = instrumentarium.list().filter(
446	            (r) => !r.definition.callableBy || r.definition.callableBy.includes('patron'),
447	          );
448	
449	          const entries = tools.map((r) => ({
450	            name: r.definition.name,
451	            route: toolNameToRoute(r.definition.name),
452	            method: permissionToMethod(r.definition.permission),
453	            description: r.definition.description,
454	            params: extractParams(r.definition.params),
455	          }));
456	
457	          return c.json(entries);
458	        });
459	
460	        // ── Static assets ────────────────────────────────────────────
461	        const staticDir = path.join(import.meta.dirname, 'static');
462	        app.get('/static/*', (c) => {
463	          const requestPath = c.req.path;
464	          const filePath = requestPath.slice('/static/'.length);
465	
466	          if (filePath.includes('..')) {
467	            return c.text('Not found', 404);
468	          }
469	
470	          const absolutePath = path.join(staticDir, filePath);
471	          try {
472	            const content = fs.readFileSync(absolutePath);
473	            const mimeType = getMimeType(absolutePath);
474	            return new Response(content, {
475	              headers: { 'Content-Type': mimeType },
476	            });
477	          } catch {
478	            return c.text('Not found', 404);
479	          }
480	        });
481	
482	        // ── Home page ────────────────────────────────────────────────
483	        app.get('/', (c) => {
484	          const config = g.guildConfig();
485	          const guildName = config.name;
486	          const navHtml = buildNavHtml(pages);
487	          const model = config.settings?.model ?? '(not set)';
488	
489	          // ── Identity card ──────────────────────────────────────────
490	          const identityCard = `<div class="card" style="margin-bottom: 16px;">
491	    <h2>Identity</h2>
492	    <table class="data-table">
493	      <tbody>
494	        <tr><td>Guild</td><td>${escapeHtml(guildName)}</td></tr>
495	        <tr><td>Nexus</td><td>${escapeHtml(VERSION)}</td></tr>
496	        <tr><td>Home</td><td>${escapeHtml(g.home)}</td></tr>
497	        <tr><td>Model</td><td>${escapeHtml(model)}</td></tr>
498	        <tr><td>Port</td><td>${port}</td></tr>
499	      </tbody>
500	    </table>
501	  </div>`;
502	
503	          // ── Warnings card (conditional) ────────────────────────────
504	          const warnings = g.startupWarnings();
505	          const warningsCard = warnings.length > 0
506	            ? `<div class="card" style="margin-bottom: 16px;">
507	    <h2>Warnings</h2>
508	    <ul>
509	      ${warnings.map((w) => `<li><span class="badge badge--warning">${escapeHtml(w)}</span></li>`).join('\n      ')}
510	    </ul>
511	  </div>`
512	            : '';
513	
514	          // ── Plugins table ──────────────────────────────────────────
515	          const apparatuses = g.apparatuses();
516	          const kits = g.kits();
517	          const failedPlugins = g.failedPlugins();
518	
519	          let pluginRows = '';
520	          if (apparatuses.length === 0 && kits.length === 0 && failedPlugins.length === 0) {
521	            pluginRows = `<tr><td colspan="4" class="empty-state">No plugins loaded.</td></tr>`;
522	          } else {
523	            pluginRows += apparatuses.map((a) =>
524	              `<tr>
525	          <td>${escapeHtml(a.id)}</td>
526	          <td>apparatus</td>
527	          <td>${escapeHtml(a.version)}</td>
528	          <td><span class="badge badge--success">apparatus</span></td>
529	        </tr>`,
530	            ).join('\n');
531	            pluginRows += kits.map((k) =>
532	              `<tr>
533	          <td>${escapeHtml(k.id)}</td>
534	          <td>kit</td>
535	          <td>${escapeHtml(k.version)}</td>
536	          <td><span class="badge badge--info">kit</span></td>
537	        </tr>`,
538	            ).join('\n');
539	            pluginRows += failedPlugins.map((f) =>
540	              `<tr>
541	          <td>${escapeHtml(f.id)}</td>
542	          <td>—</td>
543	          <td>—</td>
544	          <td><span class="badge badge--error" title="${escapeHtml(f.reason)}">failed</span> <span style="color: var(--text-dim); font-size: 11px;">${escapeHtml(f.reason)}</span></td>
545	        </tr>`,
546	            ).join('\n');
547	          }
548	
549	          const pluginsCard = `<div class="card" style="margin-bottom: 16px;">
550	    <h2>Plugins</h2>
551	    <table class="data-table">
552	      <thead>
553	        <tr><th>Id</th><th>Type</th><th>Version</th><th>Status</th></tr>
554	      </thead>
555	      <tbody>
556	        ${pluginRows}
557	      </tbody>
558	    </table>
559	  </div>`;
560	
561	          // ── Configuration card ─────────────────────────────────────
562	          let rawConfig = '';
563	          try {
564	            rawConfig = fs.readFileSync(path.join(g.home, 'guild.json'), 'utf-8');
565	          } catch {
566	            rawConfig = '(unable to read guild.json)';
567	          }
568	
569	          const configCard = `<div class="card">
570	    <details>
571	      <summary>guild.json</summary>
572	      <pre class="config-block"><code>${escapeHtml(rawConfig)}</code></pre>
573	    </details>
574	  </div>`;
575	
576	          const html = `<!DOCTYPE html>
577	<html lang="en">
578	<head>
579	  <meta charset="UTF-8">
580	  <meta name="viewport" content="width=device-width, initial-scale=1.0">
581	  <title>${escapeHtml(guildName)} — Guild Dashboard</title>
582	  <link rel="stylesheet" href="/static/style.css">
583	</head>
584	<body>
585	${navHtml}
586	<main style="padding: 24px;">
587	  <h1>${escapeHtml(guildName)}</h1>
588	  ${identityCard}
589	  ${warningsCard}
590	  ${pluginsCard}
591	  ${configCard}
592	</main>
593	</body>
594	</html>`;
595	
596	          return c.html(html);
597	        });
598	
599	        // ── Late-arriving plugins ─────────────────────────────────────
600	        ctx.on('plugin:initialized', (plugin: unknown) => {
601	          const loaded = plugin as LoadedApparatus | LoadedKit;
602	          if ('apparatus' in loaded) {
603	            scanApparatus(loaded as LoadedApparatus);
604	          } else if ('kit' in loaded) {
605	            scanKit(loaded as LoadedKit);
606	          }
607	
608	          // Check for new patron-callable tools
609	          const currentTools = instrumentarium.list().filter(
610	            (r) => !r.definition.callableBy || r.definition.callableBy.includes('patron'),
611	          );
612	          for (const resolved of currentTools) {
613	            registerToolRoute(resolved.definition, instrumentarium);
614	          }
615	        });
616	
617	        // ── Start HTTP server ─────────────────────────────────────────
618	        await new Promise<void>((resolve, reject) => {
619	          server = serve({ fetch: app.fetch, port }, () => {
620	            serverPort = port;
621	            console.log(`[oculus] Listening on http://localhost:${port}`);
622	            resolve();
623	          }) as Server;
624	          server.on('error', reject);
625	        });
626	      },
627	
628	      async stop(): Promise<void> {
629	        if (server) {
630	          await new Promise<void>((resolve, reject) => {
631	            server!.close((err) => {
632	              if (err) reject(err);
633	              else resolve();
634	            });
635	          });
636	          server = null;
637	        }
638	      },
639	
640	      supportKit: {
641	        tools: [
642	          tool({
643	            name: 'oculus',
644	            description: 'Start the Oculus web dashboard and keep it running',
645	            callableBy: ['patron'],
646	            params: {},
647	            handler: async () => {
648	              const port = api.port();
649	              console.log(`\n  Oculus is running at http://localhost:${port}/\n`);
650	              console.log('  Press Ctrl+C to stop.\n');
651	
652	              // Block until the process is interrupted.
653	              await new Promise<void>((resolve) => {
654	                const onSignal = () => { resolve(); };
655	                process.once('SIGINT', onSignal);
656	                process.once('SIGTERM', onSignal);
657	              });
658	
659	              return 'Oculus stopped.';
660	            },
661	          }),
662	        ],
663	      },
664	    },
665	  };
