154	function lookupTemplate(writType: string, config: SpiderConfig): RigTemplate {
155	  const templates = config.rigTemplates;
156	  if (templates) {
157	    if (writType in templates) return templates[writType];
158	    if ('default' in templates) return templates['default'];
