165	/**
166	 * Resolve a template engine's givens map using a variables context.
167	 * '$writ' → WritDoc, '$vars.<key>' → spiderConfig.variables[key].
168	 * Keys resolving to undefined are omitted from the output.
169	 * Non-'$' prefixed values are passed through as literals.
170	 */
171	function resolveGivens(
172	  givens: Record<string, unknown> | undefined,
173	  context: { writ: WritDoc; spiderConfig: SpiderConfig },
174	): Record<string, unknown> {
175	  const result: Record<string, unknown> = {};
176	  for (const [key, value] of Object.entries(givens ?? {})) {
177	    if (typeof value !== 'string' || !value.startsWith('$')) {
178	      result[key] = value;
179	    } else {
180	      const normalized = normalizeVarRef(value);
181	      if (normalized === '$writ') {
182	        result[key] = context.writ;
183	      } else if (/^\$vars\.[a-zA-Z_][a-zA-Z0-9_]*$/.test(normalized)) {
184	        const varKey = normalized.slice('$vars.'.length);
185	        const resolved = (context.spiderConfig.variables ?? {})[varKey];
186	        if (resolved !== undefined) {
187	          result[key] = resolved;
188	        }
189	        // undefined → omit key entirely
190	      }
191	      // Unrecognized $-prefixed strings are caught at validation time
192	    }
193	  }
194	  return result;
195	}
