200	function buildFromTemplate(
201	  template: RigTemplate,
202	  context: { writ: WritDoc; spiderConfig: SpiderConfig },
203	): { engines: EngineInstance[]; resolutionEngineId?: string } {
204	  const engines: EngineInstance[] = template.engines.map((entry) => ({
205	    id: entry.id,
206	    designId: entry.designId,
207	    status: 'pending' as const,
208	    upstream: entry.upstream ?? [],
209	    givensSpec: resolveGivens(entry.givens, context),
