214	/**
215	 * Validate all configured rig templates at startup.
216	 * Fails fast on the first error with a '[spider]' prefixed message.
217	 */
218	function validateTemplates(
219	  rigTemplates: Record<string, RigTemplate>,
220	  fabricator: FabricatorApi,
221	): void {
222	  const builtinEngineIds = new Set([
223	    draftEngine.id,
224	    implementEngine.id,
225	    reviewEngine.id,
226	    reviseEngine.id,
227	    sealEngine.id,
228	  ]);
229	
230	  for (const [templateKey, template] of Object.entries(rigTemplates)) {
231	    const engines = template.engines;
232	
233	    // R13: Non-empty check
234	    if (engines.length === 0) {
235	      throw new Error(`[spider] rigTemplates.${templateKey}: template has no engines`);
236	    }
237	
238	    // R6b: Duplicate ID check
239	    const engineIds = new Set<string>();
240	    for (const engine of engines) {
241	      if (engineIds.has(engine.id)) {
242	        throw new Error(
243	          `[spider] rigTemplates.${templateKey}: duplicate engine id "${engine.id}"`
244	        );
245	      }
246	      engineIds.add(engine.id);
247	    }
248	
249	    // R6a: designId check
250	    for (const engine of engines) {
251	      const knownInFabricator = fabricator.getEngineDesign(engine.designId) !== undefined;
252	      const knownBuiltin = builtinEngineIds.has(engine.designId);
253	      if (!knownInFabricator && !knownBuiltin) {
254	        throw new Error(
255	          `[spider] rigTemplates.${templateKey}: engine "${engine.id}" references unknown designId "${engine.designId}"`
256	        );
257	      }
258	    }
259	
260	    // R6c: Upstream reference check
261	    for (const engine of engines) {
262	      for (const upstreamId of engine.upstream ?? []) {
263	        if (!engineIds.has(upstreamId)) {
264	          throw new Error(
265	            `[spider] rigTemplates.${templateKey}: engine "${engine.id}" references unknown upstream "${upstreamId}"`
266	          );
267	        }
268	      }
269	    }
270	
271	    // R6d: Cycle detection (DFS)
272	    {
273	      const visiting = new Set<string>();
274	      const visited = new Set<string>();
275	
276	      const visit = (id: string): void => {
277	        if (visited.has(id)) return;
278	        if (visiting.has(id)) {
279	          throw new Error(
280	            `[spider] rigTemplates.${templateKey}: dependency cycle detected involving engine "${id}"`
281	          );
282	        }
283	        visiting.add(id);
284	        const engine = engines.find((e) => e.id === id)!;
285	        for (const dep of engine.upstream ?? []) {
286	          visit(dep);
287	        }
288	        visiting.delete(id);
289	        visited.add(id);
290	      };
291	
292	      for (const engine of engines) {
293	        visit(engine.id);
294	      }
295	    }
296	
297	    // R6e: resolutionEngine check
298	    if (template.resolutionEngine !== undefined && !engineIds.has(template.resolutionEngine)) {
299	      throw new Error(
