301	      );
302	    }
303	
304	    // R7: Variable reference validation
305	    for (const engine of engines) {
306	      for (const value of Object.values(engine.givens ?? {})) {
307	        if (typeof value === 'string' && value.startsWith('$')) {
308	          const normalized = normalizeVarRef(value);
309	          if (
310	            normalized === '$writ' ||
311	            /^\$vars\.[a-zA-Z_][a-zA-Z0-9_]*$/.test(normalized)
312	          ) {
313	            continue; // valid
314	          }
315	          throw new Error(
316	            `[spider] rigTemplates.${templateKey}: engine "${engine.id}" has unrecognized variable "${value}"`
317	          );
318	        }
319	      }
320	    }
321	  }
