1	/**
2	 * Crawl tool tests — unit tests for the crawl-one and crawl-continual tools.
3	 *
4	 * Tests handler logic directly (no full Spider apparatus needed), with a
5	 * minimal guild mock that provides a controllable SpiderApi stub.
6	 *
7	 * Uses the native Node test runner consistent with the rest of the package.
8	 */
9	
10	import { describe, it, beforeEach, afterEach } from 'node:test';
11	import assert from 'node:assert/strict';
12	
13	import { setGuild, clearGuild } from '@shardworks/nexus-core';
14	import type { Guild, GuildConfig, LoadedKit, LoadedApparatus } from '@shardworks/nexus-core';
15	import type { SpiderApi, SpiderConfig, CrawlResult } from '../types.ts';
16	
17	import crawlOneTool from './crawl-one.ts';
18	import crawlContinualTool from './crawl-continual.ts';
19	
20	// ── Helpers ────────────────────────────────────────────────────────────
21	
22	/** Returns a minimal guild with a controllable SpiderApi mock. */
23	function makeGuild(
24	  crawlFn: () => Promise<CrawlResult | null>,
25	  spiderConfig: Partial<SpiderConfig> = {},
26	): Guild {
27	  const mockSpider: SpiderApi = {
28	    crawl: crawlFn,
29	    show: async () => { throw new Error('not implemented'); },
30	    list: async () => [],
31	    forWrit: async () => null,
32	    resume: async () => {},
33	    getBlockType: () => undefined,
34	  };
35	
36	  const fakeGuildConfig: GuildConfig = {
37	    name: 'test-guild',
38	    nexus: '0.0.0',
39	    plugins: [],
40	    spider: spiderConfig as SpiderConfig,
41	  };
42	
43	  const fakeGuild: Guild = {
44	    home: '/tmp/test-guild',
45	    apparatus<T>(name: string): T {
46	      if (name === 'spider') return mockSpider as unknown as T;
47	      throw new Error(`Apparatus "${name}" not found`);
48	    },
49	    config<T>(_pluginId: string): T { return {} as T; },
50	    writeConfig() {},
51	    guildConfig() { return fakeGuildConfig; },
52	    kits(): LoadedKit[] { return []; },
53	    apparatuses(): LoadedApparatus[] { return []; },
54	    startupWarnings() { return []; },
55	  };
56	
57	  return fakeGuild;
58	}
59	
60	/** Returns a crawl() stub that cycles through the given sequence, then hangs. */
61	function makeCyclingCrawl(
62	  sequence: Array<CrawlResult | null>,
63	  onComplete?: () => void,
64	): () => Promise<CrawlResult | null> {
65	  let index = 0;
66	  return async () => {
67	    if (index < sequence.length) {
68	      const item = sequence[index++];
69	      if (index === sequence.length && onComplete) onComplete();
70	      return item;
71	    }
72	    // Hang the loop so tests can exit via Promise.race or similar
73	    return new Promise<CrawlResult | null>(() => {});
74	  };
75	}
76	
77	/** A sample CrawlResult for use as a non-null "work was done" sentinel. */
78	const SPAWNED: CrawlResult = { action: 'rig-spawned', rigId: 'rig-1', writId: 'writ-1' };
79	const COMPLETED: CrawlResult = { action: 'engine-completed', rigId: 'rig-1', engineId: 'draft' };
80	
81	// ── crawl-one ──────────────────────────────────────────────────────────
82	
83	describe('crawl-one tool', () => {
84	  afterEach(() => clearGuild());
85	
86	  it('has name "crawl-one"', () => {
87	    assert.equal(crawlOneTool.name, 'crawl-one');
88	  });
89	
90	  it('has the correct description', () => {
91	    assert.equal(crawlOneTool.description, "Execute one step of the Spider's crawl loop");
92	  });
93	
94	  it('requires spider:write permission', () => {
95	    assert.equal(crawlOneTool.permission, 'spider:write');
96	  });
97	
98	  it('returns a CrawlResult when work is available', async () => {
99	    setGuild(makeGuild(async () => SPAWNED));
100	    const result = await crawlOneTool.handler({});
101	    assert.deepEqual(result, SPAWNED);
102	  });
103	
104	  it('returns null when there is nothing to do', async () => {
105	    setGuild(makeGuild(async () => null));
106	    const result = await crawlOneTool.handler({});
107	    assert.equal(result, null);
108	  });
109	
110	  it('delegates directly to spider.crawl() with no transformation', async () => {
111	    const expected: CrawlResult = { action: 'engine-started', rigId: 'rig-2', engineId: 'implement' };
112	    setGuild(makeGuild(async () => expected));
113	    const result = await crawlOneTool.handler({});
114	    assert.deepEqual(result, expected);
115	  });
116	});
117	
118	// ── crawl-continual — metadata ─────────────────────────────────────────
119	
120	describe('crawl-continual tool metadata', () => {
121	  it('has name "crawl-continual"', () => {
122	    assert.equal(crawlContinualTool.name, 'crawl-continual');
123	  });
124	
125	  it('has description without "until idle" qualifier', () => {
126	    assert.equal(crawlContinualTool.description, "Run the Spider's crawl loop continuously");
127	    assert.ok(
128	      !crawlContinualTool.description.includes('until idle'),
129	      'description must not contain "until idle"',
130	    );
131	  });
132	
133	  it('requires spider:write permission', () => {
134	    assert.equal(crawlContinualTool.permission, 'spider:write');
135	  });
136	
137	  it('maxIdleCycles defaults to 0 (indefinite)', () => {
138	    const parsed = crawlContinualTool.params.parse({});
139	    assert.equal(parsed.maxIdleCycles, 0);
140	  });
141	
142	  it('instructions explain indefinite default', () => {
143	    const instructions = crawlContinualTool.instructions ?? '';
144	    assert.ok(
145	      instructions.includes('indefinitely'),
146	      'instructions must mention "indefinitely"',
147	    );
148	    assert.ok(
149	      instructions.includes('maxIdleCycles'),
150	      'instructions must mention "maxIdleCycles"',
151	    );
152	  });
153	
154	  it('maxIdleCycles param describes auto-stop behavior', () => {
155	    // In Zod v4, .description is a top-level property on the schema
156	    const shape = crawlContinualTool.params.shape as Record<string, { description?: string }>;
157	    const desc = shape['maxIdleCycles']?.description ?? '';
158	    assert.ok(
159	      desc.includes('auto-stop') || desc.includes('runs indefinitely'),
160	      `maxIdleCycles description should mention auto-stop or runs indefinitely, got: "${desc}"`,
161	    );
162	  });
163	});
164	
165	// ── crawl-continual — indefinite mode ─────────────────────────────────
166	
167	describe('crawl-continual — indefinite mode (maxIdleCycles: 0)', () => {
168	  afterEach(() => clearGuild());
169	
170	  it('does not stop after many consecutive idle cycles', async () => {
171	    // After 15 null returns, hang forever — if the loop stopped due to
172	    // idle count, the handler would resolve before the proof fires.
173	    let callCount = 0;
174	    let resolveProof!: (val: string) => void;
175	    const proof = new Promise<string>(r => { resolveProof = r; });
176	
177	    setGuild(makeGuild(async () => {
178	      callCount++;
179	      if (callCount === 15) {
180	        resolveProof('still-running');
181	        // Hang the loop so it never resolves naturally
182	        return new Promise<CrawlResult | null>(() => {});
183	      }
184	      return null;
185	    }));
186	
187	    const winner = await Promise.race([
188	      proof,
189	      crawlContinualTool.handler({ maxIdleCycles: 0, pollIntervalMs: 0 })
190	        .then(() => 'handler-resolved'),
191	    ]);
192	
193	    assert.equal(winner, 'still-running', 'loop must still be running after 15 idle cycles');
194	    assert.equal(callCount, 15);
195	  });
196	
197	  it('does not stop during alternating idle and work cycles', async () => {
198	    // idle, work, idle, work, idle ... verifies counter resets don't cause
199	    // premature termination even with many alternations.
200	    const sequence: Array<CrawlResult | null> = [
201	      null, SPAWNED, null, COMPLETED, null, SPAWNED, null, COMPLETED, null, SPAWNED,
202	    ];
203	
204	    let resolveProof!: (val: string) => void;
205	    const proof = new Promise<string>(r => { resolveProof = r; });
206	
207	    setGuild(makeGuild(makeCyclingCrawl(sequence, () => resolveProof('still-running'))));
208	
209	    const winner = await Promise.race([
210	      proof,
211	      crawlContinualTool.handler({ maxIdleCycles: 0, pollIntervalMs: 0 })
212	        .then(() => 'handler-resolved'),
213	    ]);
214	
215	    assert.equal(winner, 'still-running', 'indefinite loop must not resolve on alternating idle/work');
216	  });
217	});
218	
219	// ── crawl-continual — auto-stop mode ──────────────────────────────────
220	
221	describe('crawl-continual — auto-stop mode (positive maxIdleCycles)', () => {
222	  afterEach(() => clearGuild());
223	
224	  it('stops after maxIdleCycles=2 consecutive idles', async () => {
225	    setGuild(makeGuild(async () => null));
226	
227	    const result = await crawlContinualTool.handler({ maxIdleCycles: 2, pollIntervalMs: 0 }) as {
228	      actions: unknown[];
229	      totalActions: number;
230	    };
231	
232	    assert.deepEqual(result, { actions: [], totalActions: 0 });
233	  });
234	
235	  it('stops after maxIdleCycles=1 (single idle)', async () => {
236	    setGuild(makeGuild(async () => null));
237	
238	    const result = await crawlContinualTool.handler({ maxIdleCycles: 1, pollIntervalMs: 0 }) as {
239	      actions: unknown[];
240	      totalActions: number;
241	    };
242	
243	    assert.deepEqual(result, { actions: [], totalActions: 0 });
244	  });
245	
246	  it('collects action results in the returned summary', async () => {
247	    // Two work results followed by enough idles to stop
248	    let callCount = 0;
249	    setGuild(makeGuild(async () => {
250	      callCount++;
251	      if (callCount === 1) return SPAWNED;
252	      if (callCount === 2) return COMPLETED;
253	      return null; // Will idle to stop
254	    }));
255	
256	    const result = await crawlContinualTool.handler({ maxIdleCycles: 2, pollIntervalMs: 0 }) as {
257	      actions: unknown[];
258	      totalActions: number;
259	    };
260	
261	    assert.equal(result.totalActions, 2);
262	    assert.deepEqual(result.actions, [SPAWNED, COMPLETED]);
263	  });
264	
265	  it('resets idle counter on work and stops after trailing idles (idle, idle, work, idle, idle, idle)', async () => {
266	    // Sequence: null, null, SPAWNED, null, null, null
267	    // With maxIdleCycles=3:
268	    //   - cycle 1: null → idleCount=1
269	    //   - cycle 2: null → idleCount=2
270	    //   - cycle 3: SPAWNED → idleCount=0 (reset)
271	    //   - cycle 4: null → idleCount=1
272	    //   - cycle 5: null → idleCount=2
273	    //   - cycle 6: null → idleCount=3 → exit (idleCount >= maxIdle)
274	    const sequence: Array<CrawlResult | null> = [null, null, SPAWNED, null, null, null];
275	    let callCount = 0;
276	
277	    setGuild(makeGuild(async () => {
278	      const item = sequence[callCount++] ?? null;
279	      return item;
280	    }));
281	
282	    const result = await crawlContinualTool.handler({ maxIdleCycles: 3, pollIntervalMs: 0 }) as {
283	      actions: unknown[];
284	      totalActions: number;
285	    };
286	
287	    assert.equal(callCount, 6, 'must process all 6 cycles before stopping');
288	    assert.equal(result.totalActions, 1);
289	    assert.deepEqual(result.actions, [SPAWNED]);
290	  });
291	
292	  it('does not terminate early when work resets idle count below threshold', async () => {
293	    // Sequence: null, work, null, work, null, null → maxIdleCycles=2 → stops after trailing 2 idles
294	    const sequence: Array<CrawlResult | null> = [null, SPAWNED, null, COMPLETED, null, null];
295	    let callCount = 0;
296	
297	    setGuild(makeGuild(async () => {
298	      return sequence[callCount++] ?? null;
299	    }));
300	
301	    const result = await crawlContinualTool.handler({ maxIdleCycles: 2, pollIntervalMs: 0 }) as {
302	      actions: unknown[];
303	      totalActions: number;
304	    };
305	
306	    assert.equal(callCount, 6);
307	    assert.equal(result.totalActions, 2);
308	    assert.deepEqual(result.actions, [SPAWNED, COMPLETED]);
309	  });
310	});
311	
312	// ── crawl-continual — error handling ──────────────────────────────────
313	
314	describe('crawl-continual — error handling', () => {
315	  let originalConsoleError: typeof console.error;
316	  let errorLogs: string[];
317	
318	  beforeEach(() => {
319	    errorLogs = [];
320	    originalConsoleError = console.error;
321	    // Capture console.error calls without printing them
322	    console.error = (...args: unknown[]) => {
323	      errorLogs.push(args.map(a => (typeof a === 'string' ? a : String(a))).join(' '));
324	    };
325	  });
326	
327	  afterEach(() => {
328	    console.error = originalConsoleError;
329	    clearGuild();
330	  });
331	
332	  it('logs [crawl-continual] tag when crawl() throws an Error', async () => {
333	    setGuild(makeGuild(async () => { throw new Error('boom'); }));
334	
335	    await crawlContinualTool.handler({ maxIdleCycles: 1, pollIntervalMs: 0 });
336	
337	    assert.ok(
338	      errorLogs.some(l => l.includes('[crawl-continual]')),
339	      `expected [crawl-continual] in console.error, got: ${JSON.stringify(errorLogs)}`,
340	    );
341	  });
342	
343	  it('includes the error message in the log output', async () => {
344	    setGuild(makeGuild(async () => { throw new Error('specific error message'); }));
345	
346	    await crawlContinualTool.handler({ maxIdleCycles: 1, pollIntervalMs: 0 });
347	
348	    assert.ok(
349	      errorLogs.some(l => l.includes('specific error message')),
350	      `expected error message in log, got: ${JSON.stringify(errorLogs)}`,
351	    );
352	  });
353	
354	  it('handles non-Error throws (strings, objects)', async () => {
355	    setGuild(makeGuild(async () => { throw 'string error'; }));  // eslint-disable-line @typescript-eslint/no-throw-literal
356	
357	    await crawlContinualTool.handler({ maxIdleCycles: 1, pollIntervalMs: 0 });
358	
359	    assert.ok(
360	      errorLogs.some(l => l.includes('string error')),
361	      `expected stringified error in log, got: ${JSON.stringify(errorLogs)}`,
362	    );
363	  });
364	
365	  it('increments idle count on error and stops after maxIdleCycles errors', async () => {
366	    let callCount = 0;
367	    setGuild(makeGuild(async () => {
368	      callCount++;
369	      throw new Error(`error #${callCount}`);
370	    }));
371	
372	    const result = await crawlContinualTool.handler({ maxIdleCycles: 2, pollIntervalMs: 0 }) as {
373	      actions: unknown[];
374	      totalActions: number;
375	    };
376	
377	    assert.equal(callCount, 2, 'must call crawl() exactly maxIdleCycles times before stopping');
378	    assert.deepEqual(result, { actions: [], totalActions: 0 });
379	  });
380	
381	  it('resets idle count on success after errors', async () => {
382	    // error, error, work, error, error → with maxIdleCycles=2
383	    // after 2 errors idleCount=2 = maxIdle, but that triggers the EXIT condition...
384	    // Wait, with: error (idleCount=1), error (idleCount=2) → exits. So this won't reach work.
385	    // Instead test: error, work, error, error → maxIdleCycles=2
386	    // error: idleCount=1, work: idleCount=0, error: idleCount=1, error: idleCount=2 → exit
387	    let callCount = 0;
388	    const sequence: Array<'error' | CrawlResult | null> = ['error', SPAWNED, 'error', 'error'];
389	    setGuild(makeGuild(async () => {
390	      const item = sequence[callCount++];
391	      if (item === 'error') throw new Error(`error at #${callCount}`);
392	      return item as CrawlResult | null;
393	    }));
394	
395	    const result = await crawlContinualTool.handler({ maxIdleCycles: 2, pollIntervalMs: 0 }) as {
396	      actions: unknown[];
397	      totalActions: number;
398	    };
399	
400	    assert.equal(callCount, 4);
401	    assert.equal(result.totalActions, 1);
402	    assert.deepEqual(result.actions, [SPAWNED]);
403	  });
404	});
405	
406	// ── crawl-continual — poll interval ───────────────────────────────────
407	
408	describe('crawl-continual — poll interval configuration', () => {
409	  afterEach(() => clearGuild());
410	
411	  it('uses pollIntervalMs param over guild config', async () => {
412	    // We verify this indirectly: if the tool runs without error and the
413	    // param is accepted, the interval is being used. We set pollIntervalMs: 0
414	    // to avoid real delays and confirm the run completes quickly.
