0	/**
1	 * The Stacks — public API types.
2	 *
3	 * These types form the contract between The Stacks apparatus and all
4	 * consuming plugins. No SQLite types, no implementation details.
5	 *
6	 * See: docs/specification.md
7	 */
8	
9	// ── Plugin config ────────────────────────────────────────────────────
10	
11	/** Plugin configuration stored at guild.json["stacks"]. */
12	export interface StacksConfig {
13	  /**
14	   * Automatically apply pending database migrations when the Books are opened.
15	   * Defaults to `true` when not specified.
16	   */
17	  autoMigrate?: boolean;
18	}
19	
20	// Augment GuildConfig so `guild().config('stacks')` returns StacksConfig
21	// without requiring a manual type parameter at the call site.
22	declare module '@shardworks/nexus-core' {
23	  interface GuildConfig {
24	    stacks?: StacksConfig;
25	  }
26	}
27	
28	// ── Document model ────────────────────────────────────────────────────
29	
30	/** Every document stored in a book must satisfy this constraint. */
31	export type BookEntry = { id: string } & Record<string, unknown>;
32	
33	// ── Book schema declaration ───────────────────────────────────────────
34	
35	/**
36	 * Schema declaration for a single book in a kit's `books` contribution.
37	 *
38	 * `indexes` is a list of fields to create efficient query indexes for.
39	 * Field names use plain notation ('status') or dot-notation for nested
40	 * fields ('parent.id'). The Stacks translates internally.
41	 */
42	export interface BookSchema {
43	  indexes?: (string | string[])[];
44	}
45	
46	// ── Query language ────────────────────────────────────────────────────
47	
48	export type Scalar = string | number | boolean | null;
49	
50	export type WhereCondition =
51	  | [field: string, op: '=' | '!=', value: Scalar]
52	  | [field: string, op: '>' | '>=' | '<' | '<=', value: number | string]
53	  | [field: string, op: 'LIKE', value: string]
54	  | [field: string, op: 'IN', value: Scalar[]]
55	  | [field: string, op: 'IS NULL' | 'IS NOT NULL'];
56	
